    except Exception:
        dir_listing = []
    for name in picked:
        stem, ext = os.path.splitext(name)
        base = norm(stem)
        siblings = sorted([
            other for other in dir_listing
            if os.path.splitext(other)[1].lower() == ext.lower() and norm(os.path.splitext(other)[0]) == base
        ])
        samples.append({
            'dir': dirpath,
            'file': f"{dirpath}/{name}",
            'orig_exists': os.path.exists(os.path.join(dirpath, stem[:-4] + ext)),
            'siblings': siblings[:8],
