import os, sys, json, re, hashlib
from collections import Counter
root = sys.argv[1]

def file_hash(path):
    h = hashlib.md5()
    with open(path, 'rb') as f:
        for chunk in iter(lambda: f.read(1024*1024), b''):
            h.update(chunk)
    return h.hexdigest()

result = {
    'exact': Counter(),
    'ci_only': Counter(),
    'exact_bytes_identical': 0,
    'ci_only_bytes_identical': 0,
    'samples_different': [],
}
for dirpath, dirnames, filenames in os.walk(root):
    dirnames[:] = [d for d in dirnames if d != '@eaDir']
    listing = set(filenames)
    lower_map = {name.lower(): name for name in filenames}
    for name in filenames:
        stem, ext = os.path.splitext(name)
        if not stem.endswith(' (1)'):
            continue
        full = os.path.join(dirpath, name)
        prev = stem[:-4] + ext
        if prev in listing:
            orig_name = prev
            bucket = 'exact'
        elif prev.lower() in lower_map:
            orig_name = lower_map[prev.lower()]
            bucket = 'ci_only'
        else:
            continue
        orig = os.path.join(dirpath, orig_name)
        try:
            s1 = os.path.getsize(full)
            s2 = os.path.getsize(orig)
            same = s1 == s2 and file_hash(full) == file_hash(orig)
        except Exception as e:
            result[bucket]['errors'] += 1
            continue
        result[bucket]['total'] += 1
        if same:
            result[bucket]['identical'] += 1
            result[f'{bucket}_bytes_identical'] += s1
        else:
            result[bucket]['different'] += 1
            if len(result['samples_different']) < 10:
                result['samples_different'].append({'file': full.replace('\\','/'), 'orig': orig.replace('\\','/'), 'bucket': bucket, 'size1': s1, 'size2': s2})
print(json.dumps(result, separators=(',',':')))
