import os, sys, json, re, hashlib
from collections import Counter, defaultdict
roots = sys.argv[1:]
num_re = re.compile(r' \((\d+)\)$')

def norm(stem):
    return num_re.sub('', stem)

def md5(path):
    h = hashlib.md5()
    with open(path, 'rb') as f:
        for chunk in iter(lambda: f.read(1024*1024), b''):
            h.update(chunk)
    return h.hexdigest()

report = {}
for root in roots:
    counts = Counter()
    ext_counts = Counter()
    dir_counts = Counter()
    safe_bytes = 0
    samples = {'identical': [], 'different_with_original': [], 'numbered_set_no_plain': [], 'lone_orphan': [], 'case_only_original': []}
    for dirpath, dirnames, filenames in os.walk(root):
        dirnames[:] = [d for d in dirnames if d != '@eaDir']
        listing = filenames
        exact_set = set(listing)
        lower_map = {name.lower(): name for name in listing}
        for name in filenames:
            stem, ext = os.path.splitext(name)
            work = stem
            chain = 0
            while work.endswith(' (1)'):
                work = work[:-4]
                chain += 1
            if chain == 0:
                continue
            counts['total'] += 1
            counts['multi' if chain > 1 else 'single'] += 1
            ext_counts[ext.lower() or '<noext>'] += 1
            dir_counts[dirpath.replace('\\','/')] += 1
            prev = stem[:-4] + ext
            full = os.path.join(dirpath, name)
            rec = {'file': full.replace('\\','/')}
            if prev in exact_set:
                counts['exact_original_exists'] += 1
                orig = os.path.join(dirpath, prev)
                try:
                    same = os.path.getsize(full) == os.path.getsize(orig) and md5(full) == md5(orig)
                except Exception:
                    counts['hash_errors'] += 1
                    continue
                if same:
                    counts['exact_identical'] += 1
                    safe_bytes += os.path.getsize(full)
                    if len(samples['identical']) < 3:
                        rec['orig'] = orig.replace('\\','/')
                        samples['identical'].append(rec)
                else:
                    counts['exact_different'] += 1
                    if len(samples['different_with_original']) < 3:
                        rec['orig'] = orig.replace('\\','/')
                        samples['different_with_original'].append(rec)
                continue
            if prev.lower() in lower_map:
                counts['case_only_original'] += 1
                if len(samples['case_only_original']) < 3:
                    rec['orig'] = os.path.join(dirpath, lower_map[prev.lower()]).replace('\\','/')
                    samples['case_only_original'].append(rec)
                continue
            base = norm(stem)
            sibs = [other for other in listing if os.path.splitext(other)[1].lower() == ext.lower() and norm(os.path.splitext(other)[0]) == base]
            if len(sibs) > 1:
                counts['numbered_set_no_plain'] += 1
                if len(samples['numbered_set_no_plain']) < 3:
                    rec['siblings'] = sorted(sibs)[:6]
                    samples['numbered_set_no_plain'].append(rec)
            else:
                counts['lone_orphan'] += 1
                if len(samples['lone_orphan']) < 3:
                    samples['lone_orphan'].append(rec)
    report[root] = {
        'counts': counts,
        'safe_bytes': safe_bytes,
        'top_exts': ext_counts.most_common(8),
        'top_dirs': dir_counts.most_common(8),
