import re, json, os
from collections import Counter, defaultdict
files = [f'/volume1/@synologydrive/log/client.log_{i}' for i in range(0,40)] + ['/volume1/@synologydrive/log/client.log']
interesting = {'ahazan','mcameron','bschiap','tshah','MCardoso','NSchuchman','mzabo','adweck','dsmith','ijianchan','Disney','Star Wars','Decor','shared','SharedLic','wait for designer approve','Aardman Animations','One Piece','Synology Reports'}
by_day_root = defaultdict(Counter)
by_day_fake = defaultdict(Counter)
for fp in files:
    if not os.path.exists(fp):
        continue
    with open(fp, 'r', encoding='utf-8', errors='ignore') as f:
        for line in f:
            mdate = re.match(r'(\d{4}-\d{2}-\d{2})T', line)
            if not mdate:
                continue
            day = mdate.group(1)
            m = re.search(r"'(/[^']+)'", line)
            path = m.group(1) if m else None
            if not path:
                m = re.search(r"\[(/[^\]]+)\]", line)
                path = m.group(1) if m else None
            if not path:
                continue
            parts = path.split('/')
            root = parts[1] if len(parts) > 1 else '/'
            if root not in interesting:
                continue
            by_day_root[day][root] += 1
            if 'File not modified, this could be a fake event' in line:
                by_day_fake[day][root] += 1
out = {
  'events_by_day': {day: cnt.most_common(10) for day, cnt in sorted(by_day_root.items())[-12:]},
  'fake_by_day': {day: cnt.most_common(10) for day, cnt in sorted(by_day_fake.items())[-12:]},
}
print(json.dumps(out, separators=(',',':')))
